/**
 * AST node types that represent TypeScript type contexts.
 * Identifiers appearing in these contexts are type references, not value references.
 */
const TYPE_NODES = new Set([
    'TSTypeReference',
    'TSInterfaceHeritage',
    'TSClassImplements',
    'TSTypeQuery',
    'TSQualifiedName',
]);
/**
 * Checks if a node appears in a TypeScript type context.
 *
 * This is used to avoid flagging identifiers that are only used as types,
 * not as runtime values.
 *
 * For example:
 * - type FetchFn = typeof fetch; // fetch is in type context
 * - interface Client { fetch: typeof fetch; } // fetch is in type context
 * - const x = fetch('url'); // fetch is NOT in type context
 *
 * @param node - The AST node to check
 * @returns True if the node appears in a TypeScript type context
 */
export const isInTypeContext = (node) => {
    // ESLint populates the parent property at runtime, but it's not in the type definitions
    const parent = node.parent;
    return parent ? TYPE_NODES.has(parent.type) : false;
};
/**
 * Checks if an identifier is a local variable (not global), excluding imports.
 *
 * This uses ESLint's scope analysis to determine if an identifier
 * refers to a locally declared variable or parameter, but NOT an import.
 *
 * For example:
 * - fetch('url') where fetch is global → returns false
 * - const { fetch } = hubspot; fetch('url') → returns true
 * - function test(fetch) { fetch(); } → returns true
 * - import fetch from 'lib'; fetch() → returns false (import, not local)
 */
export const isLocalVariable = (context, node, identifierName) => {
    const scope = context.sourceCode.getScope(node);
    // Walk up the scope chain from current scope to global scope
    let currentScope = scope;
    while (currentScope) {
        // Check if this scope has a variable with the given name
        const variable = currentScope.variables.find((v) => v.name === identifierName);
        if (variable && variable.defs.length > 0) {
            // Check if any definition is an import
            // ImportBinding means this variable was defined via an import statement
            const isImport = variable.defs.some((def) => def.type === 'ImportBinding');
            if (isImport) {
                // This is an imported name, not a local variable
                return false;
            }
            // This is a local variable (const/let/var/parameter)
            return true;
        }
        // Move to parent scope
        currentScope = currentScope.upper;
    }
    // Not found in any scope - it's global
    return false;
};
